const output = $input.first().json.stdout;
const files = output.split('\n').filter(f => f.trim());

return files.map(file => ({
  json: {
    file_path: file,
    file_name: file.split('/').pop(),
    discovered_at: new Date().toISOString()
  }
}));

const content = $input.first().binary.data.toString('utf8');
const fileName = $('Process Each Note').first().json.file_name;

// Determine source type from filename or frontmatter
let sourceType = 'unknown';
if (fileName.startsWith('voice_')) sourceType = 'voice';
else if (fileName.startsWith('link_')) sourceType = 'web_link';
else if (fileName.startsWith('text_')) sourceType = 'text';
else if (fileName.startsWith('screenshot_')) sourceType = 'screenshot';

// Extract frontmatter if exists
const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---/);
if (frontmatterMatch) {
  const fm = frontmatterMatch[1];
  const sourceMatch = fm.match(/source:\s*(.+)/);
  if (sourceMatch) sourceType = sourceMatch[1].trim();
}

return [{
  json: {
    file_path: $('Process Each Note').first().json.file_path,
    file_name: fileName,
    source_type: sourceType,
    content: content,
    content_length: content.length,
    word_count: content.split(/\s+/).length
  }
}];

const allResults = $input.all();

const summary = {
  total_processed: allResults.length,
  by_source: {
    voice: allResults.filter(r => r.json.source_type === 'voice').length,
    text: allResults.filter(r => r.json.source_type === 'text').length,
    web_link: allResults.filter(r => r.json.source_type === 'web_link').length,
    screenshot: allResults.filter(r => r.json.source_type === 'screenshot').length
  },
  sent_to_tier2: allResults.filter(r => r.json.sent_to_tier2).length,
  sent_to_tier3: allResults.filter(r => r.json.sent_to_tier3).length,
  processed_at: new Date().toISOString()
};

return [{ json: summary }];
